#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch
		                                  = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
ll n, m, a[MAXN];
int cmd[MAXN], x[MAXN], y[MAXN];
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin >> n >> m;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
	}
	for (int i = 1; i <= m; ++i)
	{
		cin >> cmd[i] >> x[i] >> y[i];

	}
	for (int i = m; i; --i)
	{
		if (cmd[i] == 1)
		{
			if (x[i] == y[i])
			{
				a[x[i]] /= 2;
			}
			else
			{
				a[x[i]] -= a[y[i]];
			}
		}
		else
		{
			if (x[i] == y[i])
			{
				a[x[i]] = sqrt(a[x[i]]);
			}
			else
			{
				a[x[i]] /= a[y[i]];
			}
		}
	}
	for (int i = 1; i <= n; ++i)
	{
		cout << a[i] << ' ';
	}
	return false;
}
